const randomMinutes = Math. floor (Math. random() * 600) + 1;
const delayMs = randomMinutes * 60 * 1000;

return [
{
json: {
delay: delayMs,
minutes: randomMinutes
}
}
  ];

const url = $input.first().json.data.url

const match = url.match(/tmpfiles\.org\/(\d+)\/([^\/?#]+)/);

if (match && match[1] && match[2]) {
return [
  {
json: {
fileNumber: match[1],
fileName: match[2]
}
}
];
} else {
throw new Error("Could not extract file number or file name from URL");
}
